  // Residency
  'apply.residency.title':  { en:'Residency transfer', da:'Bopælsskifte', sv:'Flytt av folkbokföring', nb:'Bostedsoverføring', nn:'Bustadoverføring', se:'Ássinbáikki sirdin', de:'Wohnsitzverlegung', fr:'Transfert de résidence', pl:'Zmiana miejsca zamieszkania', ar:'نقل الإقامة', uk:'Зміна місця проживання', fi:'Asuinpaikan siirto' },
  'apply.residency.lede':   { en:'A single guided application that updates your civil registration with the relevant Nordic authority.', da:'Én vejledt ansøgning, der opdaterer din folkeregistrering hos den relevante nordiske myndighed.', sv:'En guidad ansökan som uppdaterar din folkbokföring hos rätt nordisk myndighet.', nb:'Én veiledet søknad som oppdaterer folkeregistreringen din hos riktig nordisk myndighet.', nn:'Éin rettleidd søknad som oppdaterer folkeregistreringa di hos rett nordisk mynde.', se:'Okta bagaduvvon ohcamuš mii ođastuhttá du ássiidčállosa rievttes davviriikkalaš eiseválddis.', de:'Ein geführter Antrag, der Ihre Meldedaten bei der zuständigen nordischen Behörde aktualisiert.', fr:'Une demande guidée unique qui met à jour votre inscription civile auprès de l’autorité nordique compétente.', pl:'Jeden przewodnik aktualizujący Twoją rejestrację u właściwego organu nordyckiego.', ar:'طلب موجَّه واحد يُحدّث تسجيلك المدني لدى الجهة النوردية المختصة.', uk:'Єдина керована заявка, що оновлює ваш цивільний облік у відповідному скандинавському органі.', fi:'Yksi ohjattu hakemus, joka päivittää väestökirjauksesi oikealle pohjoismaiselle viranomaiselle.' },
