  // Tax cert
  'apply.taxCert.title':    { en:'Tax residency certificate', da:'Skatteboligattest', sv:'Hemvistintyg för skatt', nb:'Skattemessig bostedsattest', nn:'Skattemessig bustadsattest', se:'Vearroássama duođaštus', de:'Steueransässigkeitsbescheinigung', fr:'Certificat de résidence fiscale', pl:'Zaświadczenie o rezydencji podatkowej', ar:'شهادة الإقامة الضريبية', uk:'Сертифікат податкового резидентства', fi:'Verotuksellinen asuinpaikkatodistus' },
  'apply.taxCert.lede':     { en:'Request an official certificate of your tax residency, signed by the competent authority.', da:'Anmod om en officiel attest på din skattepligt, underskrevet af den kompetente myndighed.', sv:'Begär ett officiellt intyg om din skatterättsliga hemvist, signerat av behörig myndighet.', nb:'Be om et offisielt sertifikat for din skattemessige bopel, signert av kompetent myndighet.', nn:'Be om eit offisielt sertifikat for skatterettsleg bustad, signert av kompetent mynde.', se:'Bivdde almmolaš duođaštusa du vearroássamis, vuolláičállojuvvon gelbbolaš eiseválddis.', de:'Beantragen Sie eine offizielle Bescheinigung Ihrer steuerlichen Ansässigkeit, signiert von der zuständigen Behörde.', fr:'Demandez un certificat officiel de votre résidence fiscale, signé par l’autorité compétente.', pl:'Wnioskuj o oficjalne zaświadczenie o rezydencji podatkowej, podpisane przez właściwy urząd.', ar:'اطلب شهادة رسمية بإقامتك الضريبية، موقَّعة من الجهة المختصة.', uk:'Запитайте офіційний сертифікат податкового резидентства, підписаний компетентним органом.', fi:'Tilaa virallinen verotuksellinen asuinpaikkatodistus, jonka allekirjoittaa toimivaltainen viranomainen.' },

  // Child benefit
  'apply.childBenefit.title': { en:'Child & family benefit', da:'Børne- og familieydelse', sv:'Barn- och familjebidrag', nb:'Barnetrygd og familieytelser', nn:'Barnetrygd og familieytingar', se:'Mánáid- ja bearašdoarjja', de:'Kinder- und Familienleistung', fr:'Allocation enfant et famille', pl:'Świadczenia rodzinne', ar:'إعانة الأطفال والأسرة', uk:'Допомога на дітей і сім’ю', fi:'Lapsi- ja perhe-etuus' },
  'apply.childBenefit.lede':  { en:'Apply for child or family benefits. Upload supporting documents — we extract the data and pre-check eligibility before a caseworker decides.', da:'Søg om børne- eller familieydelse. Upload bilag — vi udtrækker data og forhåndsvurderer berettigelsen, før en sagsbehandler træffer beslutning.', sv:'Ansök om barn- eller familjebidrag. Ladda upp underlag — vi läser ut data och förhandsbedömer rätten innan en handläggare beslutar.', nb:'Søk om barnetrygd eller familieytelser. Last opp vedlegg — vi henter ut data og forhåndsvurderer retten før en saksbehandler beslutter.', nn:'Søk om barnetrygd eller familieytingar. Last opp vedlegg — vi hentar ut data og førehandsvurderer retten før ein saksbehandlar avgjer.', se:'Oza mánáid- dahje bearašdoarjaga. Bidja čuovus dokumeanttaid — mii čoaggit dieđuid ja ovddalgihtii árvvoštallat vuoigatvuođa ovdal go áššiidgieđahalli mearrida.', de:'Beantragen Sie Kinder- oder Familienleistung. Belege hochladen — wir entnehmen die Daten und prüfen den Anspruch vor, bevor eine Sachbearbeitung entscheidet.', fr:'Demandez une allocation enfant ou famille. Téléversez vos pièces — nous extrayons les données et pré-vérifions l’éligibilité avant qu’un agent ne décide.', pl:'Wnioskuj o świadczenia rodzinne. Wgraj dokumenty — wyciągniemy dane i wstępnie ocenimy uprawnienia, zanim urzędnik podejmie decyzję.', ar:'قدّم طلبًا لإعانة الأطفال أو الأسرة. حمّل المستندات الداعمة — نستخرج البيانات ونتحقق من الأهلية قبل قرار الموظف.', uk:'Подайте заяву на допомогу на дитину чи сім’ю. Завантажте підтвердні документи — ми зчитаємо дані та попередньо оцінимо право, перш ніж рішення ухвалить фахівець.', fi:'Hae lapsi- tai perhe-etuutta. Lataa liitteet — poimimme tiedot ja arvioimme oikeuden alustavasti ennen käsittelijän päätöstä.' },

