  'cases.title':            { en:'My cases', da:'Mine sager', sv:'Mina ärenden', nb:'Mine saker', nn:'Mine saker', se:'Mu áššit', de:'Meine Vorgänge', fr:'Mes dossiers', pl:'Moje sprawy', ar:'قضاياي', uk:'Мої справи', fi:'Asiani' },
